export interface Effect {
    id: string;
    type: string;
    x: number;
    y: number;
    duration: number;
    elapsed: number;
    active: boolean;
    data: Record<string, unknown>;
}

export interface EffectConfig {
    type: string;
    x: number;
    y: number;
    duration?: number;
    data?: Record<string, unknown>;
}

export class EffectSystem {
    private engine: unknown;
    private effects: Map<string, Effect> = new Map();
    private effectIdCounter: number = 0;
    private initialized: boolean = false;

    constructor(engine: unknown) {
        this.engine = engine;
    }

    async initialize(): Promise<void> {
        console.log('💫 EffectSystem 初始化...');
        this.initialized = true;
        console.log('✅ EffectSystem 初始化完成');
    }

    create(config: EffectConfig): Effect {
        const id = `effect_${++this.effectIdCounter}`;
        const effect: Effect = {
            id,
            type: config.type,
            x: config.x,
            y: config.y,
            duration: config.duration ?? 1000,
            elapsed: 0,
            active: true,
            data: config.data ?? {}
        };

        this.effects.set(id, effect);
        return effect;
    }

    flash(x: number, y: number, color: string = '#ffffff', duration: number = 200): Effect {
        return this.create({
            type: 'flash',
            x,
            y,
            duration,
            data: { color }
        });
    }

    shake(intensity: number = 10, duration: number = 300): Effect {
        return this.create({
            type: 'shake',
            x: 0,
            y: 0,
            duration,
            data: { intensity, originalX: 0, originalY: 0 }
        });
    }

    explosion(x: number, y: number, radius: number = 50): Effect {
        return this.create({
            type: 'explosion',
            x,
            y,
            duration: 500,
            data: { radius, maxRadius: radius }
        });
    }

    heal(x: number, y: number): Effect {
        return this.create({
            type: 'heal',
            x,
            y,
            duration: 1000,
            data: {}
        });
    }

    damage(x: number, y: number, value: number): Effect {
        return this.create({
            type: 'damage',
            x,
            y,
            duration: 1500,
            data: { value, offsetY: 0 }
        });
    }

    levelUp(x: number, y: number): Effect {
        return this.create({
            type: 'levelup',
            x,
            y,
            duration: 2000,
            data: {}
        });
    }

    update(deltaTime: number): void {
        for (const [id, effect] of this.effects) {
            if (!effect.active) {
                this.effects.delete(id);
                continue;
            }

            effect.elapsed += deltaTime;

            if (effect.elapsed >= effect.duration) {
                effect.active = false;
                this.effects.delete(id);
            }
        }
    }

    render(ctx: CanvasRenderingContext2D): void {
        for (const effect of this.effects.values()) {
            if (!effect.active) continue;

            const progress = effect.elapsed / effect.duration;

            switch (effect.type) {
                case 'flash':
                    this.renderFlash(ctx, effect, progress);
                    break;
                case 'explosion':
                    this.renderExplosion(ctx, effect, progress);
                    break;
                case 'damage':
                    this.renderDamage(ctx, effect, progress);
                    break;
                case 'heal':
                    this.renderHeal(ctx, effect, progress);
                    break;
                case 'levelup':
                    this.renderLevelUp(ctx, effect, progress);
                    break;
            }
        }
    }

    private renderFlash(ctx: CanvasRenderingContext2D, effect: Effect, progress: number): void {
        const alpha = 1 - progress;
        const color = effect.data.color as string ?? '#ffffff';
        
        ctx.globalAlpha = alpha;
        ctx.fillStyle = color;
        ctx.beginPath();
        ctx.arc(effect.x, effect.y, 30 * (1 + progress), 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1;
    }

    private renderExplosion(ctx: CanvasRenderingContext2D, effect: Effect, progress: number): void {
        const radius = (effect.data.maxRadius as number) * progress;
        const alpha = 1 - progress;

        ctx.globalAlpha = alpha;
        ctx.strokeStyle = '#ff6600';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.arc(effect.x, effect.y, radius, 0, Math.PI * 2);
        ctx.stroke();
        ctx.globalAlpha = 1;
    }

    private renderDamage(ctx: CanvasRenderingContext2D, effect: Effect, progress: number): void {
        const offsetY = -50 * progress;
        const alpha = progress < 0.5 ? 1 : 2 - progress * 2;

        ctx.globalAlpha = alpha;
        ctx.font = 'bold 24px Arial';
        ctx.fillStyle = '#ff4444';
        ctx.textAlign = 'center';
        ctx.fillText(`-${effect.data.value}`, effect.x, effect.y + offsetY);
        ctx.globalAlpha = 1;
    }

    private renderHeal(ctx: CanvasRenderingContext2D, effect: Effect, progress: number): void {
        const offsetY = -30 * progress;
        const alpha = 1 - progress;

        ctx.globalAlpha = alpha;
        ctx.font = 'bold 20px Arial';
        ctx.fillStyle = '#44ff44';
        ctx.textAlign = 'center';
        ctx.fillText('+HP', effect.x, effect.y + offsetY);
        ctx.globalAlpha = 1;
    }

    private renderLevelUp(ctx: CanvasRenderingContext2D, effect: Effect, progress: number): void {
        const scale = 1 + Math.sin(progress * Math.PI) * 0.5;
        const alpha = progress < 0.7 ? 1 : (1 - progress) / 0.3;

        ctx.globalAlpha = alpha;
        ctx.font = `bold ${24 * scale}px Arial`;
        ctx.fillStyle = '#ffdd00';
        ctx.textAlign = 'center';
        ctx.fillText('LEVEL UP!', effect.x, effect.y - 50 * progress);
        ctx.globalAlpha = 1;
    }

    stop(id: string): void {
        const effect = this.effects.get(id);
        if (effect) {
            effect.active = false;
            this.effects.delete(id);
        }
    }

    stopAll(): void {
        this.effects.clear();
    }

    destroy(): void {
        this.effects.clear();
        this.initialized = false;
    }
}

export default EffectSystem;
